function parseRange(s) {
  const parts = s.split('-');
  if (parts.length === 2) {
    const a = parseInt(parts[0], 10);
    const b = parseInt(parts[1], 10);
    if (a <= b) {
      const result = [];
      for (let i = a; i <= b; i++) result.push(i);
      return result;
    } else {
      const result = [];
      for (let i = a; i >= b; i--) result.push(i);
      return result;
    }
  }
  return [parseInt(s, 10)];
}
